class MetadataBuilder:
    """Builds gRPC metadata from HTTP headers and user input."""

    # Headers that should be forwarded from HTTP to gRPC
    FORWARDED_HEADERS = {
        'x-request-id',
        'x-correlation-id',
        'x-trace-id',
        'x-span-id',
        'x-user-id',
        'x-tenant-id',
        'x-api-key',
        'authorization',
        'accept-language',
        'x-forwarded-for',
        'x-forwarded-host',
        'user-agent',
        'x-custom-header',
    }

    # Headers that should never be forwarded
    BLOCKED_HEADERS = {
        'host',
        'content-length',
        'content-type',
        'connection',
        'transfer-encoding',
    }

    def __init__(self):
        self._metadata: List[Tuple[str, str]] = []

    def add(self, key: str, value: str) -> 'MetadataBuilder':
        """Add a single metadata entry."""
        sanitized_key = key.lower().strip()
        if sanitized_key not in self.BLOCKED_HEADERS:
            self._metadata.append((sanitized_key, value))
        return self

    def add_from_http_headers(self, headers: Dict[str, str]) -> 'MetadataBuilder':
        """Extract relevant headers from HTTP request and add as metadata."""
        for key, value in headers.items():
            normalized_key = key.lower().strip()
            if normalized_key in self.FORWARDED_HEADERS:
                self._metadata.append((normalized_key, value))
        return self

    def add_from_user_input(self, user_metadata: Dict[str, str]) -> 'MetadataBuilder':
        """Add metadata from user-provided input."""
        for key, value in user_metadata.items():
            sanitized_key = key.lower().strip()
            if sanitized_key not in self.BLOCKED_HEADERS:
                # Prefix user metadata to avoid collisions
                prefixed_key = f"x-user-{sanitized_key}" if not sanitized_key.startswith('x-') else sanitized_key
                self._metadata.append((prefixed_key, str(value)))
        return self

    def add_gateway_metadata(self, gateway_id: str = "api-gateway-1") -> 'MetadataBuilder':
        """Add API gateway specific metadata."""
        import time
        import uuid
        self._metadata.append(("x-gateway-id", gateway_id))
        self._metadata.append(("x-gateway-timestamp", str(int(time.time() * 1000))))
        # Add request ID if not already present
        existing_keys = {k for k, v in self._metadata}
        if 'x-request-id' not in existing_keys:
            self._metadata.append(("x-request-id", str(uuid.uuid4())))
        return self

    def build(self) -> List[Tuple[str, str]]:
        """Build and return the metadata list."""
        return list(self._metadata)

    def clear(self) -> 'MetadataBuilder':
        """Clear all metadata."""
        self._metadata.clear()
        return self


