class MetadataLoggingInterceptor(grpc.UnaryUnaryClientInterceptor,
                                  grpc.UnaryStreamClientInterceptor):
    """Interceptor that logs metadata for debugging."""

    def intercept_unary_unary(self, continuation, client_call_details, request):
        print(f"[MetadataLog] Calling: {client_call_details.method}")
        if client_call_details.metadata:
            for key, value in client_call_details.metadata:
                # Mask sensitive headers
                display_value = "***" if key in ('authorization', 'x-api-key') else value
                print(f"  [Metadata] {key}: {display_value}")
        return continuation(client_call_details, request)

    def intercept_unary_stream(self, continuation, client_call_details, request):
        print(f"[MetadataLog] Streaming call: {client_call_details.method}")
        if client_call_details.metadata:
            for key, value in client_call_details.metadata:
                display_value = "***" if key in ('authorization', 'x-api-key') else value
                print(f"  [Metadata] {key}: {display_value}")
        return continuation(client_call_details, request)


class RetryInterceptor(grpc.UnaryUnaryClientInterceptor):
    """Interceptor that retries failed calls."""

    RETRYABLE_CODES = {
        grpc.StatusCode.UNAVAILABLE,
        grpc.StatusCode.DEADLINE_EXCEEDED,
        grpc.StatusCode.RESOURCE_EXHAUSTED,
    }

    def __init__(self, max_retries: int = 3, backoff_factor: float = 0.5):
        self.max_retries = max_retries
        self.backoff_factor = backoff_factor

    def intercept_unary_unary(self, continuation, client_call_details, request):
        import time
        last_error = None
        for attempt in range(self.max_retries + 1):
            try:
                response = continuation(client_call_details, request)
                return response
            except grpc.RpcError as e:
                last_error = e
                if e.code() not in self.RETRYABLE_CODES or attempt == self.max_retries:
                    raise
                sleep_time = self.backoff_factor * (2 ** attempt)
                print(f"[Retry] Attempt {attempt + 1}/{self.max_retries}, "
                      f"sleeping {sleep_time}s, error: {e.code()}")
                time.sleep(sleep_time)
        raise last_error


