class ApiGatewayServicer(grpc.GenericRpcHandler):
    """
    API Gateway servicer that receives requests and forwards them
    to appropriate backend services with metadata propagation.
    """

    def __init__(self, service_registry: Dict[str, str]):
        """
        Args:
            service_registry: Mapping of service names to their gRPC addresses
                             e.g., {"user-service": "localhost:50051", 
                                    "order-service": "localhost:50052"}
        """
        self.service_registry = service_registry
        self.clients: Dict[str, BackendServiceClient] = {}
        self._initialize_clients()

    def _initialize_clients(self):
        """Initialize gRPC clients for all registered backend services."""
        for service_name, address in self.service_registry.items():
            self.clients[service_name] = BackendServiceClient(
                target=address,
                secure=False,
                timeout=30.0,
            )

    def get_client(self, service_name: str) -> BackendServiceClient:
        """Get or create a client for the specified service."""
        if service_name not in self.clients:
            if service_name not in self.service_registry:
                raise ValueError(f"Unknown service: {service_name}")
            self.clients[service_name] = BackendServiceClient(
                target=self.service_registry[service_name],
                secure=False,
            )
        return self.clients[service_name]

    def close_all(self):
        """Close all backend connections."""
        for client in self.clients.values():
            client.close()
        self.clients.clear()


