class GatewayServicer:
    """
    Gateway gRPC servicer that receives calls, extracts metadata,
    and forwards to backend services while propagating metadata.
    """

    def __init__(self, service_registry: Dict[str, str]):
        self.service_registry = service_registry
        self.backend_clients: Dict[str, BackendServiceClient] = {}
        for name, addr in service_registry.items():
            self.backend_clients[name] = BackendServiceClient(target=addr)

    def ForwardRequest(self, request, context):
        """
        Generic forward handler that propagates metadata to backend.
        """
        # Extract incoming metadata from the client/HTTP layer
        incoming_metadata = dict(context.invocation_metadata())
        print(f"\n[Gateway] Incoming metadata:")
        for k, v in incoming_metadata.items():
            print(f"  {k}: {v}")

        # Determine target service (from metadata or routing logic)
        target_service = incoming_metadata.get('x-target-service', 'echo-service')
        target_method = incoming_metadata.get('x-target-method', ECHO_METHOD)

        if target_service not in self.backend_clients:
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"Service '{target_service}' not found in registry")
            return b''

        # Build metadata for the backend call
        metadata_builder = MetadataBuilder()
        metadata_builder.add_from_http_headers(incoming_metadata)
        metadata_builder.add_gateway_metadata(gateway_id="api-gateway-main")

        backend_metadata = metadata_builder.build()

        # Forward to backend
        client = self.backend_clients[target_service]
        try:
            response, trailing_metadata, call = client.unary_unary_call(
                method=target_method,
                request=request,
                metadata=backend_metadata,
            )

            # Propagate trailing metadata from backend back to the caller
            trailing_md_list = list(trailing_metadata) if trailing_metadata else []
            # Add gateway's own trailing metadata
            trailing_md_list.append(("x-gateway-processed", "true"))
            context.set_trailing_metadata(trailing_md_list)

            return response

        except BackendServiceError as e:
            context.set_code(e.code)
            context.set_details(f"Backend error: {e.message}")
            context.set_trailing_metadata([
                ("x-gateway-error", "true"),
                ("x-error-service", target_service),
            ])
            return b''

    def close(self):
        for client in self.backend_clients.values():
            client.close()


def create_gateway_server(port: int = 50050, service_registry: Dict[str, str] = None):
    """Create and start the API gateway gRPC server."""
    if service_registry is None:
        service_registry = {"echo-service": "localhost:50051"}

    server = grpc.server(futures.ThreadPoolExecutor(max_workers=20))
    gateway_servicer = GatewayServicer(service_registry)

    GATEWAY_METHOD = "/gateway.ApiGateway/ForwardRequest"

    class GatewayHandler(grpc.GenericRpcHandler):
        def service(self, handler_call_details):
            # Route all calls through the gateway forwarder
            if handler_call_details.method == GATEWAY_METHOD:
                return grpc.unary_unary_rpc_method_handler(
                    gateway_servicer.ForwardRequest,
                    request_deserializer=None,
                    response_serializer=None,
                )
            return None

    server.add_generic_rpc_handlers([GatewayHandler()])
    server.add_insecure_port(f'[::]:{port}')
    return server, gateway_servicer


