class ApiGatewayClient:
    """
    Client that simulates sending requests through the API gateway.
    Accepts HTTP-like headers and converts them to gRPC metadata.
    """

    def __init__(self, gateway_address: str = "localhost:50050"):
        self.channel = grpc.insecure_channel(gateway_address)
        self.gateway_method = "/gateway.ApiGateway/ForwardRequest"

    def send_request(
        self,
        request_body: str,
        http_headers: Dict[str, str],
        target_service: str = "echo-service",
        target_method: str = ECHO_METHOD,
        user_metadata: Optional[Dict[str, str]] = None,
    ) -> Dict:
        """
        Send a request through the gateway with HTTP headers converted to gRPC metadata.
        """
        # Build metadata from HTTP headers and user input
        metadata_builder = MetadataBuilder()
        metadata_builder.add_from_http_headers(http_headers)
        metadata_builder.add("x-target-service", target_service)
        metadata_builder.add("x-target-method", target_method)

        if user_metadata:
            metadata_builder.add_from_user_input(user_metadata)

        metadata = metadata_builder.build()

        # Make the gRPC call
        stub = self.channel.unary_unary(
            self.gateway_method,
            request_serializer=None,
            response_deserializer=None,
        )

        try:
            response, call = stub.with_call(
                request_body.encode('utf-8'),
                metadata=metadata,
                timeout=30.0,
            )

            trailing_metadata = dict(call.trailing_metadata())

            return {
                "status": "success",
                "response": response.decode('utf-8') if isinstance(response, bytes) else response,
                "trailing_metadata": trailing_metadata,
                "grpc_status": call.code().name,
            }
        except grpc.RpcError as e:
            return {
                "status": "error",
                "error_code": e.code().name,
                "error_message": e.details(),
            }

    def close(self):
        self.channel.close()

    def __enter__(self):
        return self

    def __exit__(self, *args):
        self.close()


